cd /tmp && cat > cl-test-good.md <<'EOF'
## [0.11.0] - 2026-04-22

### feat
- new feature

# Changelog

All notable changes.

## [Unreleased]

## [0.10.0] - 2026-04-20

### feat
- prior
EOF

awk '
  BEGIN { new_entry=""; preamble=""; rest=""; section=0; seen_title=0 }
  section==0 && !seen_title && /^# Changelog$/ { seen_title=1; section=1 }
  section==1 && /^## \[[0-9]/ { section=2 }
  { if (section==0) new_entry=new_entry $0 "\n";
    else if (section==1) preamble=preamble $0 "\n";
    else rest=rest $0 "\n" }
  END {
    if (!seen_title) { print "restore-preamble: # Changelog title not found" > "/dev/stderr"; exit 1 }
    printf "%s%s%s", preamble, new_entry, rest
  }
' cl-test-good.md && echo "---GOOD OK---"

